/*
 * Process Communication System Program
 * Demonstrates how communication system programs work (like pipe, fork)
 * This implements a simple version of the 'pipe' and basic process creation
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>

#define BUFFER_SIZE 1024
#define READ_END 0
#define WRITE_END 1

/* 
 * Example 1: Simple pipe demonstration
 * Similar to: ls | grep "txt"
 */
void demonstrate_pipe() {
 printf("\n--- Pipe Demonstration (like: ls | grep pattern) ---\n\n");

 int pipefd[2];
 pid_t pid;

 /* Create a pipe */
 if (pipe(pipefd) == -1) {
 perror("pipe");
 return;
 }

 pid = fork();

 if (pid < 0) {
 perror("fork");
 return;
 }

 if (pid == 0) {
 /* Child process - executes 'ls' and writes to pipe */
 close(pipefd[READ_END]); /* Close read end */

 /* Redirect stdout to pipe write end */
 dup2(pipefd[WRITE_END], STDOUT_FILENO);
 close(pipefd[WRITE_END]);

 /* Execute 'ls' command */
 execlp("ls", "ls", "-la", NULL);
 perror("execlp");
 exit(1);
 } else {
 /* Parent process - reads from pipe */
 char buffer[BUFFER_SIZE];
 ssize_t bytes_read;

 close(pipefd[WRITE_END]); /* Close write end */

 printf("Child process (ls) output received by parent:\n");
 printf("----------------------------------------\n");

 /* Read from pipe and filter for .c files */
 while ((bytes_read = read(pipefd[READ_END], buffer, BUFFER_SIZE - 1)) > 0) {
 buffer[bytes_read] = '\0';
 /* Simple filter - print only lines containing .c */
 char *line = strtok(buffer, "\n");
 while (line != NULL) {
 if (strstr(line, ".c") != NULL || strstr(line, ".h") != NULL) {
 printf(" %s\n", line);
 }
 line = strtok(NULL, "\n");
 }
 }

 close(pipefd[READ_END]);
 wait(NULL); /* Wait for child */
 printf("----------------------------------------\n");
 }
}

/*
 * Example 2: File I/O using system calls
 * Demonstrates file management system programs
 */
void demonstrate_file_ops() {
 printf("\n--- File Operations Demonstration ---\n\n");

 const char *filename = "system_program_demo.txt";
 const char *content = "This is a test file created by a system program.\n"
 "System programs use system calls to interact with the kernel.\n"
 "This demonstrates file management capabilities.\n";

 /* Create and write file - like 'cat > file' */
 int fd = open(filename, O_WRONLY | O_CREAT | O_TRUNC, 0644);
 if (fd < 0) {
 perror("open for write");
 return;
 }

 ssize_t written = write(fd, content, strlen(content));
 if (written < 0) {
 perror("write");
 close(fd);
 return;
 }

 close(fd);
 printf("✓ Created file: %s (%ld bytes)\n", filename, written);

 /* Read and display file - like 'cat file' */
 fd = open(filename, O_RDONLY);
 if (fd < 0) {
 perror("open for read");
 return;
 }

 char buffer[BUFFER_SIZE];
 ssize_t bytes_read = read(fd, buffer, BUFFER_SIZE - 1);
 if (bytes_read > 0) {
 buffer[bytes_read] = '\0';
 printf("\n✓ File contents read via system call:\n");
 printf("----------------------------------------\n");
 printf("%s", buffer);
 printf("----------------------------------------\n");
 }

 close(fd);

 /* Delete file - like 'rm file' */
 if (unlink(filename) == 0) {
 printf("✓ Deleted file: %s\n", filename);
 }
}

/*
 * Example 3: Process status - similar to 'ps' command
 */
void demonstrate_process_info() {
 printf("\n--- Process Information (like: ps) ---\n\n");

 printf("Current Process Information:\n");
 printf("----------------------------------------\n");
 printf(" Process ID (PID): %d\n", getpid());
 printf(" Parent Process ID: %d\n", getppid());
 printf(" User ID (UID): %d\n", getuid());
 printf(" Group ID (GID): %d\n", getgid());
 printf("----------------------------------------\n");
}

/*
 * Example 4: Directory operations - similar to 'ls' and 'mkdir'
 */
void demonstrate_directory_ops() {
 printf("\n--- Directory Operations ---\n\n");

 /* Get current directory - like 'pwd' */
 char cwd[BUFFER_SIZE];
 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("Current working directory (pwd): %s\n", cwd);
 }

 /* Note: Directory creation and listing would require
 * additional system calls like mkdir(), opendir(), readdir(), closedir()
 * This is similar to how 'mkdir' and 'ls' system programs work */

 printf("\nNote: Directory listing uses opendir()/readdir() system calls\n");
 printf("These are the same calls used by the 'ls' system program\n");
}

int main() {
 printf("========================================\n");
 printf(" System Programs Demonstration in C\n");
 printf(" (File Management, Process, Pipe)\n");
 printf("========================================\n");

 /* Demonstrate various system program concepts */
 demonstrate_process_info();
 demonstrate_directory_ops();
 demonstrate_file_ops();
 demonstrate_pipe();

 printf("\n========================================\n");
 printf("All these operations use SYSTEM CALLS\n");
 printf("which are the interface between\n");
 printf("system programs and the kernel!\n");
 printf("========================================\n\n");

 return 0;
}

/*
 * Program Loading and Linking Concept Demonstration
 * Shows how dynamic linking works (similar to how ld.so works)
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dlfcn.h> /* Dynamic linking library */
#include <unistd.h>

/* Function pointer type for dynamically loaded functions */
typedef int (*MathFunction)(int a, int b);

/*
 * Simulated object module structure
 * Represents compiled but unlinked code
 */
typedef struct {
 char name[64];
 void *code_address;
 int size;
 char dependencies[5][32]; /* External symbols needed */
 int dep_count;
} ObjectModule;

/*
 * Symbol table entry
 * Represents a symbol that can be resolved during linking
 */
typedef struct {
 char name[64];
 void *address;
 int is_defined;
} Symbol;

/* Simulated symbol table */
Symbol symbol_table[20];
int symbol_count = 0;

/*
 * Add symbol to symbol table
 * Simulates symbol resolution during linking
 */
void add_symbol(const char *name, void *addr, int defined) {
 if (symbol_count < 20) {
 strcpy(symbol_table[symbol_count].name, name);
 symbol_table[symbol_count].address = addr;
 symbol_table[symbol_count].is_defined = defined;
 symbol_count++;
 }
}

/*
 * Resolve symbol from shared library
 * Similar to what dynamic linker (ld.so) does at runtime
 */
void *resolve_symbol(const char *name) {
 printf(" [Dynamic Linker] Resolving symbol: %s\n", name);

 /* First check local symbol table */
 for (int i = 0; i < symbol_count; i++) {
 if (strcmp(symbol_table[i].name, name) == 0) {
 if (symbol_table[i].is_defined) {
 printf(" [Dynamic Linker] Found in local table at %p\n", 
 symbol_table[i].address);
 return symbol_table[i].address;
 }
 }
 }

 /* In real dynamic linking, would search shared libraries here */
 return NULL;
}

/*
 * Simulated library functions that would be in a .so file
 */
int add_impl(int a, int b) {
 return a + b;
}

int multiply_impl(int a, int b) {
 return a * b;
}

int subtract_impl(int a, int b) {
 return a - b;
}

/*
 * Demonstrate dynamic loading using dlopen/dlsym
 * This is how programs load shared libraries at runtime
 */
void demonstrate_dynamic_loading() {
 printf("\n=== Dynamic Loading Demonstration ===\n");
 printf("(Similar to how programs load .so libraries)\n\n");

 /* For demonstration, we'll simulate what dynamic loading does
 * In practice, you would use: 
 * void *handle = dlopen("./libmath.so", RTLD_LAZY);
 * MathFunction func = (MathFunction)dlsym(handle, "add");
 */

 /* Register our "library" functions */
 printf("[1] Loading library functions...\n");
 add_symbol("add", (void*)add_impl, 1);
 add_symbol("multiply", (void*)multiply_impl, 1);
 add_symbol("subtract", (void*)subtract_impl, 1);

 printf("[2] Functions registered in symbol table\n\n");

 /* Resolve and call functions */
 printf("[3] Program requests 'add' function...\n");
 int (*add)(int, int) = (int (*)(int, int))resolve_symbol("add");
 if (add) {
 int result = add(10, 5);
 printf("[4] Called add(10, 5) = %d\n\n", result);
 }

 printf("[5] Program requests 'multiply' function...\n");
 int (*multiply)(int, int) = (int (*)(int, int))resolve_symbol("multiply");
 if (multiply) {
 int result = multiply(10, 5);
 printf("[6] Called multiply(10, 5) = %d\n\n", result);
 }
}

/*
 * Demonstrate program loading phases
 * Similar to how the OS loader works
 */
void demonstrate_loading_phases() {
 printf("\n=== Program Loading Phases ===\n");
 printf("(Shows steps from source to execution)\n\n");

 printf("Phase 1: SOURCE CODE\n");
 printf(" - Program written in high-level language\n\n");

 printf("Phase 2: COMPILATION\n");
 printf(" - Compiler (e.g., gcc) translates to object code\n");
 printf(" - Output: .o file with machine code\n\n");

 printf("Phase 3: LINKING\n");
 printf(" - Linker combines object files\n");
 printf(" - Resolves external symbols\n");
 printf(" - Creates executable file\n\n");

 printf("Phase 4: LOADING (at runtime)\n");
 printf(" - Loader reads executable into memory\n");
 printf(" - Dynamic linker resolves shared library symbols\n");
 printf(" - Sets up process address space\n");
 printf(" - Transfers control to program entry point (main)\n\n");

 printf("Phase 5: EXECUTION\n");
 printf(" - Program runs in user space\n");
 printf(" - Makes system calls via kernel\n\n");
}

/*
 * Show memory layout of a loaded program
 */
void demonstrate_memory_layout() {
 printf("\n=== Typical Process Memory Layout ===\n\n");

 printf("High Address\n");
 printf("+------------------\n");
 printf("| Stack | <- local variables, function calls\n");
 printf("+------------------\n");
 printf("| ↓ |\n");
 printf("| ↑ |\n");
 printf("+------------------\n");
 printf("| Heap | <- dynamic memory (malloc)\n");
 printf("+------------------\n");
 printf("| BSS | <- uninitialized data\n");
 printf("+------------------\n");
 printf("| Data | <- initialized global variables\n");
 printf("+------------------\n");
 printf("| Text | <- executable code (instructions)\n");
 printf("+------------------\n");
 printf("Low Address\n\n");

 /* Show actual addresses in this process */
 printf("Actual addresses in this process:\n");
 printf(" Code (text): %p\n", (void*)demonstrate_memory_layout);
 printf(" Stack: %p\n", (void*)&demonstrate_memory_layout);
 printf(" Heap (malloc): %p\n", (void*)malloc(1));
 printf(" Static data: %p\n", (void*)&symbol_table);
 printf("\n");
}

int main() {
 printf("========================================\n");
 printf(" Program Loading & Linking Demo\n");
 printf(" (Loader, Linker, Dynamic Loading)\n");
 printf("========================================\n");

 demonstrate_loading_phases();
 demonstrate_dynamic_loading();
 demonstrate_memory_layout();

 printf("========================================\n");
 printf("These concepts are used by system\n");
 printf("programs like: ld, ld.so, loader\n");
 printf("========================================\n");

 return 0;
}
